<?php
namespace App\Controllers; use App\Libraries\FeatureSchema; use App\Libraries\JwtAuth; use CodeIgniter\RESTful\ResourceController; class UserController extends ResourceController { private function getAuthUser(): ?array { $header = $this->request->getHeaderLine('Authorization'); $decoded = JwtAuth::decodeFromHeader($header); if (! $decoded || empty($decoded->uid)) { return null; } $userModel = new \App\Models\UserModel(); return $userModel->find((int) $decoded->uid); } private function autoProcessWithdrawals(int $userId) { $db = \Config\Database::connect(); $db->table('withdrawals') ->where('user_id', $userId) ->where('status', 'pending') ->where('created_at <=', date('Y-m-d H:i:s', strtotime('-3 minutes'))) ->update([ 'status' => 'withdrawn', 'processed_at' => date('Y-m-d H:i:s') ]); } public function getProfile() { $user = $this->getAuthUser(); if (!$user) return $this->failUnauthorized(); $db = \Config\Database::connect(); $freshUser = $db->table('users')->where('user_id', $user['user_id'])->get()->getRowArray(); unset($freshUser['password_hash']); if ((int)($freshUser['verification_status'] ?? 0) !== 1 || ($freshUser['role'] ?? '') === 'admin') { $freshUser['promo_discount'] = 0.0; if (($freshUser['role'] ?? '') === 'admin' && (float)$freshUser['promo_discount'] > 0) { $db->table('users')->where('user_id', $user['user_id'])->update(['promo_discount' => 0.0]); } } else { if ((float)$freshUser['promo_discount'] === 0.0 && ($freshUser['account_type'] ?? '') === 'student') { $level = strtolower($freshUser['education_level'] ?? ''); $freshUser['promo_discount'] = ($level === 'tertiary') ? 20.0 : 15.0; $db->table('users')->where('user_id', $user['user_id'])->update(['promo_discount' => $freshUser['promo_discount']]); } } return $this->respond($freshUser); } public function getHistory() { FeatureSchema::ensure(); $user = $this->getAuthUser(); if (!$user) return $this->failUnauthorized('Authentication required.'); $this->autoProcessWithdrawals((int)$user['user_id']); $db = \Config\Database::connect(); $transactions = $db->table('user_transactions') ->select('user_transactions.transaction_type, user_transactions.amount, user_transactions.payment_method, user_transactions.created_at, user_transactions.note, resources.title as resource_title') ->join('resources', 'resources.resource_id = user_transactions.resource_id', 'left') ->where('user_transactions.user_id', $user['user_id']) ->get() ->getResultArray(); $earnings = $db->table('user_transactions') ->select('user_transactions.transaction_type, user_transactions.uploader_amount as amount, user_transactions.payment_method, user_transactions.created_at, user_transactions.note, resources.title as resource_title') ->join('resources', 'resources.resource_id = user_transactions.resource_id') ->where('resources.uploader_id', $user['user_id']) ->where('user_transactions.uploader_amount >', 0) ->get() ->getResultArray(); foreach ($earnings as &$e) { $e['transaction_type'] = 'earning_' . $e['transaction_type']; if ($e['transaction_type'] === 'earning_material_open') { $e['note'] = 'System Incentive Earned'; } else if ($e['transaction_type'] === 'earning_purchase') { $e['note'] = 'Sale Revenue Earned'; } } $withdrawals = $db->table('withdrawals') ->select('status as transaction_type, amount, method as payment_method, created_at, account_name as note, NULL as resource_title') ->where('user_id', $user['user_id']) ->get() ->getResultArray(); foreach ($withdrawals as &$w) { $w['transaction_type'] = 'withdrawal_' . $w['transaction_type']; } $history = array_merge($transactions, $earnings, $withdrawals); usort($history, function($a, $b) { return strtotime($b['created_at']) - strtotime($a['created_at']); }); return $this->respond($history); } public function uploadProfileImage() { FeatureSchema::ensure(); $user = $this->getAuthUser(); if (!$user) return $this->failUnauthorized('Authentication required.'); $file = $this->request->getFile('profile_image'); if (!$file || !$file->isValid()) { return $this->fail('Invalid file uploaded.'); } $allowedExtensions = ['jpg', 'jpeg', 'png', 'gif', 'webp']; if (!in_array(strtolower($file->getClientExtension()), $allowedExtensions, true)) { return $this->fail('Invalid image format. Allowed: ' . implode(', ', $allowedExtensions), 400); } $uploadPath = FCPATH . 'uploads/profiles/'; if (!is_dir($uploadPath)) { mkdir($uploadPath, 0777, true); } $newName = $file->getRandomName(); $file->move($uploadPath, $newName); $imagePath = 'uploads/profiles/' . $newName; $userModel = new \App\Models\UserModel(); $userModel->update($user['user_id'], ['profile_image_path' => $imagePath]); return $this->respond([ 'message' => 'Profile image updated successfully.', 'profile_image_path' => $imagePath ]); } public function reVerifyUser() { FeatureSchema::ensure(); $user = $this->getAuthUser(); if (!$user) return $this->failUnauthorized('Authentication required.'); $db = \Config\Database::connect(); $freshUser = $db->table('users')->where('user_id', $user['user_id'])->get()->getRowArray(); if ((int)$freshUser['verification_status'] !== 2) { return $this->fail('Re-submission only allowed for rejected accounts.', 400); } if ((int)$freshUser['verification_attempts'] >= 3) { return $this->fail('Maximum verification attempts (3/3) reached.', 403); } $proofFile = $this->request->getFile('proof_file'); if (!$proofFile || !$proofFile->isValid()) { return $this->fail('A valid ID document is required for re-submission.', 400); } $newName = $proofFile->getRandomName(); $proofFile->move(FCPATH . 'uploads', $newName); $updateData = [ 'proof_file_path' => 'uploads/' . $newName, 'verification_status' => 0, 'verification_attempts' => (int)$freshUser['verification_attempts'] + 1, 'promo_discount' => 0.0 ]; $db->table('users')->where('user_id', $user['user_id'])->update($updateData); return $this->respond([ 'message' => 'ID re-submitted successfully. Your account is now pending review.', 'verification_status' => 0, 'attempts' => $updateData['verification_attempts'] ]); } public function getUploaderEarnings() { FeatureSchema::ensure(); $user = $this->getAuthUser(); if (!$user) return $this->failUnauthorized('Authentication required.'); $this->autoProcessWithdrawals((int)$user['user_id']); $db = \Config\Database::connect(); $sales = $db->table('resource_purchases') ->select('resource_purchases.purchased_at, resource_purchases.uploader_amount, resources.title as resource_title, users.name as buyer_name') ->join('resources', 'resources.resource_id = resource_purchases.resource_id') ->join('users', 'users.user_id = resource_purchases.user_id') ->where('resources.uploader_id', $user['user_id']) ->get() ->getResultArray(); $incentives = $db->table('user_transactions') ->select('user_transactions.created_at as purchased_at, user_transactions.uploader_amount, resources.title as resource_title, users.name as buyer_name') ->join('resources', 'resources.resource_id = user_transactions.resource_id') ->join('users', 'users.user_id = user_transactions.user_id') ->where('resources.uploader_id', $user['user_id']) ->where('user_transactions.transaction_type', 'material_open') ->where('user_transactions.uploader_amount >', 0) ->get() ->getResultArray(); foreach ($incentives as &$inc) { $inc['buyer_name'] = 'System Incentive (' . $inc['buyer_name'] . ')'; } $allEarnings = array_merge($sales, $incentives); usort($allEarnings, function($a, $b) { return strtotime($b['purchased_at']) - strtotime($a['purchased_at']); }); $totalEarnings = 0; foreach ($allEarnings as $earning) { $totalEarnings += (float)$earning['uploader_amount']; } return $this->respond([ 'total_earnings' => round($totalEarnings, 2), 'sales_count' => count($allEarnings), 'sales_history' => $allEarnings ]); } public function getPayoutInfo() { FeatureSchema::ensure(); $user = $this->getAuthUser(); if (!$user) return $this->failUnauthorized(); $db = \Config\Database::connect(); $accounts = $db->table('payout_accounts') ->where('user_id', $user['user_id']) ->orderBy('created_at', 'ASC') ->get() ->getResultArray(); $hasPin = $db->table('users') ->select('payout_pin') ->where('user_id', $user['user_id']) ->get() ->getRowArray(); return $this->respond([ 'has_setup' => count($accounts) > 0 && $hasPin && $hasPin['payout_pin'] !== null, 'accounts' => $accounts, 'has_pin' => $hasPin && $hasPin['payout_pin'] !== null, ]); } public function addPayoutAccount() { FeatureSchema::ensure(); $user = $this->getAuthUser(); if (!$user) return $this->failUnauthorized(); $type = $this->request->getVar('account_type'); $number = $this->request->getVar('account_number'); $name = $this->request->getVar('account_name'); $cardNumber = $this->request->getVar('card_number'); $expiry = $this->request->getVar('expiry_date'); $cvv = $this->request->getVar('cvv'); if (!in_array($type, ['gcash', 'maya', 'bank'], true)) { return $this->fail('Invalid account type.', 400); } if (empty($number) || empty($name)) { return $this->fail('Account number and name are required.', 400); } if ($type === 'bank') { if (empty($cardNumber) || empty($expiry) || empty($cvv)) { return $this->fail('Card number, expiry date, and CVV are required for bank accounts.', 400); } if (!preg_match('/^\d{13,19}$/', preg_replace('/\s+/', '', $cardNumber))) { return $this->fail('Invalid card number.', 400); } if (!preg_match('/^\d{3,4}$/', $cvv)) { return $this->fail('Invalid CVV.', 400); } } $db = \Config\Database::connect(); $count = $db->table('payout_accounts') ->where('user_id', $user['user_id']) ->where('account_type', $type) ->countAllResults(); if ($count >= 3) { return $this->fail("Maximum of 3 {$type} accounts allowed.", 400); } $data = [ 'user_id' => $user['user_id'], 'account_type' => $type, 'account_number' => $number, 'account_name' => $name, ]; if ($type === 'bank') { $data['card_number'] = preg_replace('/\s+/', '', $cardNumber); $data['expiry_date'] = $expiry; $data['cvv'] = $cvv; } $db->table('payout_accounts')->insert($data); return $this->respondCreated(['message' => ucfirst($type) . ' account added successfully.']); } public function deletePayoutAccount($accountId = null) { FeatureSchema::ensure(); $user = $this->getAuthUser(); if (!$user) return $this->failUnauthorized(); $db = \Config\Database::connect(); $account = $db->table('payout_accounts') ->where('account_id', $accountId) ->where('user_id', $user['user_id']) ->get() ->getRowArray(); if (!$account) return $this->failNotFound('Account not found.'); $db->table('payout_accounts')->delete(['account_id' => $accountId]); return $this->respondDeleted(['message' => 'Account removed.']); } public function savePayoutPin() { FeatureSchema::ensure(); $user = $this->getAuthUser(); if (!$user) return $this->failUnauthorized(); $pin = $this->request->getVar('pin'); if (!preg_match('/^\d{6}$/', $pin)) { return $this->fail('PIN must be exactly 6 digits.', 400); } $db = \Config\Database::connect(); $db->table('users') ->where('user_id', $user['user_id']) ->update(['payout_pin' => password_hash($pin, PASSWORD_DEFAULT)]); return $this->respond(['message' => 'Payout PIN saved successfully.']); } public function requestWithdrawal() { FeatureSchema::ensure(); $user = $this->getAuthUser(); if (!$user) return $this->failUnauthorized(); $amount = (float)$this->request->getVar('amount'); $pin = $this->request->getVar('pin'); $accountId = (int)$this->request->getVar('account_id'); if ($amount < 100) return $this->fail('Minimum withdrawal is ???100.00', 400); if (!$accountId) return $this->fail('Payout account is required.', 400); $db = \Config\Database::connect(); $stored = $db->table('users') ->select('payout_pin') ->where('user_id', $user['user_id']) ->get() ->getRowArray(); if (!$stored || !$stored['payout_pin']) { return $this->fail('Please set up your payout PIN first.', 400); } if (!password_verify($pin, $stored['payout_pin'])) { return $this->fail('Incorrect payout PIN.', 400); } $account = $db->table('payout_accounts') ->where('account_id', $accountId) ->where('user_id', $user['user_id']) ->get() ->getRowArray(); if (!$account) return $this->fail('Payout account not found.', 400); $salesSum = $db->table('resource_purchases') ->join('resources', 'resources.resource_id = resource_purchases.resource_id') ->where('resources.uploader_id', $user['user_id']) ->selectSum('uploader_amount') ->get()->getRowArray()['uploader_amount'] ?? 0; $incentivesSum = $db->table('user_transactions') ->join('resources', 'resources.resource_id = user_transactions.resource_id') ->where('resources.uploader_id', $user['user_id']) ->where('user_transactions.transaction_type', 'material_open') ->selectSum('uploader_amount') ->get()->getRowArray()['uploader_amount'] ?? 0; $withdrawSum = $db->table('withdrawals') ->where('user_id', $user['user_id']) ->whereIn('status', ['pending', 'withdrawn']) ->selectSum('amount') ->get()->getRowArray()['amount'] ?? 0; $balance = (float)$salesSum + (float)$incentivesSum - (float)$withdrawSum; if ($amount > $balance) { return $this->fail('Insufficient balance for this withdrawal.', 400); } $db->table('withdrawals')->insert([ 'user_id' => $user['user_id'], 'amount' => $amount, 'method' => $account['account_type'], 'account_number' => $account['account_number'], 'account_name' => $account['account_name'], 'status' => 'pending' ]); return $this->respondCreated(['message' => 'Withdrawal request submitted. It will be processed in approx. 3 minutes.']); } public function getPurchases() { FeatureSchema::ensure(); $user = $this->getAuthUser(); if (!$user) return $this->failUnauthorized('Authentication required.'); $db = \Config\Database::connect(); $purchases = $db->table('resource_purchases') ->select('
                resource_purchases.purchased_at,
                resource_purchases.paid_amount,
                resource_purchases.listed_price,
                resource_purchases.discount_percent,
                resource_purchases.payment_method,
                resources.resource_id,
                resources.title,
                resources.cover_image_path,
                resources.file_path,
                resources.material_type,
                users.name as uploader_name
            ') ->join('resources', 'resources.resource_id = resource_purchases.resource_id') ->join('users', 'users.user_id = resources.uploader_id', 'left') ->where('resource_purchases.user_id', $user['user_id']) ->where('resource_purchases.status', 'completed') ->orderBy('resource_purchases.purchased_at', 'DESC') ->get() ->getResultArray(); return $this->respond($purchases); } public function getWithdrawals() { FeatureSchema::ensure(); $user = $this->getAuthUser(); if (!$user) return $this->failUnauthorized(); $this->autoProcessWithdrawals((int)$user['user_id']); $db = \Config\Database::connect(); $list = $db->table('withdrawals') ->where('user_id', $user['user_id']) ->orderBy('created_at', 'DESC') ->get()->getResultArray(); return $this->respond($list); } } 
